import{_ as a,o as e,c as i,a5 as s}from"./chunks/framework.D9Kapg2s.js";const g=JSON.parse('{"title":"术语表管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/glossary.md","filePath":"zh/guide/glossary.md"}'),l={name:"zh/guide/glossary.md"};function d(o,t,r,n,h,c){return e(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="术语表管理" tabindex="-1">术语表管理 <a class="header-anchor" href="#术语表管理" aria-label="Permalink to &quot;术语表管理&quot;">​</a></h1><p>术语表用于确保专业术语在翻译过程中保持一致。每个项目拥有独立的术语表，术语规则在翻译时自动应用。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>术语表与项目绑定，术语条目存储在项目级别。启用术语表后，翻译引擎会在每段翻译时自动查询匹配的术语，将其作为提示传给 LLM，确保术语翻译的一致性。</p><h2 id="启用术语表" tabindex="-1">启用术语表 <a class="header-anchor" href="#启用术语表" aria-label="Permalink to &quot;启用术语表&quot;">​</a></h2><ol><li>进入项目工作区</li><li>在项目设置中启用 <strong>术语表</strong> 开关（<code>glossary_enabled</code>）</li><li>添加术语条目后，翻译时将自动应用术语规则</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>术语表默认关闭，需要手动启用才会在翻译中生效。</p></div><h2 id="术语条目" tabindex="-1">术语条目 <a class="header-anchor" href="#术语条目" aria-label="Permalink to &quot;术语条目&quot;">​</a></h2><p>每个术语条目包含以下字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>source</td><td>string</td><td>原始语言中的术语（必填）</td></tr><tr><td>target</td><td>string</td><td>翻译后的术语（必填）</td></tr><tr><td>case_sensitive</td><td>boolean</td><td>匹配时是否区分大小写（默认 <code>false</code>）</td></tr><tr><td>notes</td><td>string</td><td>术语的补充说明（可选）</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>源术语 (EN)</th><th>目标术语 (ZH)</th><th>区分大小写</th><th>备注</th></tr></thead><tbody><tr><td>API</td><td>API</td><td>否</td><td>不翻译</td></tr><tr><td>Kubernetes</td><td>Kubernetes</td><td>否</td><td>不翻译</td></tr><tr><td>container</td><td>容器</td><td>否</td><td></td></tr><tr><td>deployment</td><td>部署</td><td>否</td><td></td></tr><tr><td>MySQL</td><td>MySQL</td><td>是</td><td>数据库名称，区分大小写</td></tr></tbody></table><h2 id="创建术语条目" tabindex="-1">创建术语条目 <a class="header-anchor" href="#创建术语条目" aria-label="Permalink to &quot;创建术语条目&quot;">​</a></h2><ol><li>进入项目工作区的 <strong>术语表</strong> 选项卡</li><li>点击 <strong>新建术语条目</strong></li><li>在侧边抽屉中填写源术语、目标术语、是否区分大小写及备注</li><li>确认保存</li></ol><div class="warning custom-block"><p class="custom-block-title">重复检查</p><p>同一项目内不允许存在相同的源术语。系统会自动将 <code>source</code> 转为小写进行去重校验（唯一索引 <code>project_id + source_key</code>）。如果提交重复的源术语，将返回 <code>exists</code> 错误。</p></div><h2 id="编辑术语条目" tabindex="-1">编辑术语条目 <a class="header-anchor" href="#编辑术语条目" aria-label="Permalink to &quot;编辑术语条目&quot;">​</a></h2><p>编辑术语条目时，如果 <strong>目标术语（target）发生变更</strong>，API 会返回 <code>target_changed: true</code> 标志，提示用户可能需要同步更新已翻译的内容。</p><h2 id="导入导出" tabindex="-1">导入导出 <a class="header-anchor" href="#导入导出" aria-label="Permalink to &quot;导入导出&quot;">​</a></h2><h3 id="csv-导入" tabindex="-1">CSV 导入 <a class="header-anchor" href="#csv-导入" aria-label="Permalink to &quot;CSV 导入&quot;">​</a></h3><p>支持通过 CSV 文件批量导入术语。在术语表面板中点击 <strong>导入</strong> 按钮，上传 CSV 文件。</p><p>CSV 格式要求：</p><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">source,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">target,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">case_sensitive,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">notes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">API,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">API,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">false,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">不翻译</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Kubernetes,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Kubernetes,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">false,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">不翻译</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">container,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">容器,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">false,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deployment,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">部署,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">false,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MySQL,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MySQL,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">true,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">数据库名称</span></span></code></pre></div><p>导入结果将返回：</p><ul><li><code>added</code>：成功导入的条目数</li><li><code>skipped</code>：跳过的条目列表，包含行号、源术语和跳过原因（<code>duplicate</code>、<code>invalid_entry</code>、<code>short_row</code>）</li></ul><h3 id="csv-导出" tabindex="-1">CSV 导出 <a class="header-anchor" href="#csv-导出" aria-label="Permalink to &quot;CSV 导出&quot;">​</a></h3><p>在术语表面板中点击 <strong>导出</strong> 按钮，将当前项目的术语表导出为 CSV 文件，方便在不同项目间共享或备份。</p><h2 id="术语同步更新" tabindex="-1">术语同步更新 <a class="header-anchor" href="#术语同步更新" aria-label="Permalink to &quot;术语同步更新&quot;">​</a></h2><p>当术语条目的目标术语发生变更时，已翻译的内容不会自动更新。系统提供了<strong>术语同步</strong>功能，可以批量更新已翻译段落中的旧译文。</p><h3 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h3><p>术语同步是一个多步骤的异步流程：</p><ol><li><p><strong>影响分析</strong> — 系统采用两阶段匹配策略分析受影响的段落：</p><ul><li>阶段 1：原文（<code>source_text</code>）包含术语的源术语</li><li>阶段 2：译文（<code>target_text</code>）包含旧的目标术语</li><li>仅匹配状态为 <code>translated</code>、<code>edited</code>、<code>approved</code> 或 <code>rejected</code> 的段落</li><li>支持限定特定资源范围进行分析</li></ul></li><li><p><strong>提交同步任务</strong> — 确认影响范围后，提交异步同步任务。系统会创建 <code>SyncTask</code> 记录，返回任务 ID 和状态轮询端点。</p></li><li><p><strong>执行替换</strong> — 后台 Worker 分批处理（每批 100 个段落），使用安全替换算法更新译文：</p><ul><li>CJK 语言直接替换</li><li>拉丁语系按词边界替换，避免误替换</li><li>替换后的段落状态自动设为 <code>edited</code>，需要人工复核</li></ul></li><li><p><strong>查询进度</strong> — 前端以 500ms 间隔轮询任务状态端点，实时显示处理进度。</p></li><li><p><strong>取消任务</strong> — 支持取消正在执行的同步任务。<code>pending</code> 状态直接取消，<code>running</code> 状态在当前批次完成后停止。</p></li></ol><h3 id="同步任务状态" tabindex="-1">同步任务状态 <a class="header-anchor" href="#同步任务状态" aria-label="Permalink to &quot;同步任务状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>pending</td><td>等待执行</td></tr><tr><td>running</td><td>正在执行</td></tr><tr><td>completed</td><td>执行完成</td></tr><tr><td>failed</td><td>执行失败</td></tr><tr><td>cancelled</td><td>已取消</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">超时清理</p><p>超过 24 小时未完成的同步任务会被自动标记为 <code>failed</code>。</p></div><h2 id="自动提取术语-bootstrap" tabindex="-1">自动提取术语（Bootstrap） <a class="header-anchor" href="#自动提取术语-bootstrap" aria-label="Permalink to &quot;自动提取术语（Bootstrap）&quot;">​</a></h2><p>LinguaFlow 支持在翻译过程中自动从源文本中提取术语，使用独立的术语抽取提示词模板。</p><h3 id="独立提取" tabindex="-1">独立提取 <a class="header-anchor" href="#独立提取" aria-label="Permalink to &quot;独立提取&quot;">​</a></h3><p>在翻译前单独运行术语提取阶段，使用 LLM 从源文件中识别专业术语并生成术语条目。使用独立的术语抽取提示词模板（<code>/bootstrap-prompt-templates</code>），提取结果以 JSON 格式返回，自动写入术语表。</p><p>在执行计划的 Bootstrap 配置中启用独立提取，或在执行计划中添加提取轮次（<code>mode: extract</code>）。</p><h3 id="内联提取" tabindex="-1">内联提取 <a class="header-anchor" href="#内联提取" aria-label="Permalink to &quot;内联提取&quot;">​</a></h3><p>在翻译过程中，LLM 可以同时返回新发现的术语。系统采用 <strong>First-Wins</strong> 策略合并术语：</p><ul><li>新术语自动写入运行时术语表</li><li>如果同一源术语已存在但目标不同，以表中已有版本为准（跳过新增）</li><li>当 <code>inline_conflict_strategy</code> 设为 <code>rewrite_local</code> 时，会自动将本批译文中的冲突目标改写为权威版本，确保文档内一致性</li></ul><h3 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h3><p>在执行配置（Execution Profile）中可调整以下参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>bootstrap.enabled</td><td>是否启用术语自动提取</td></tr><tr><td>bootstrap.max_terms_per_1000_chars</td><td>每 1000 字符最多提取的术语数</td></tr><tr><td>bootstrap.min_source_len</td><td>源术语最小长度（默认 2 个字符）</td></tr><tr><td>bootstrap.inline_conflict_strategy</td><td>内联冲突策略（<code>off</code> / <code>rewrite_local</code>）</td></tr></tbody></table><h2 id="术语精简-glossary-prune" tabindex="-1">术语精简（Glossary Prune） <a class="header-anchor" href="#术语精简-glossary-prune" aria-label="Permalink to &quot;术语精简（Glossary Prune）&quot;">​</a></h2><p>随着术语表增长，可能出现冗余条目、含义冲突或用例稀少的问题。术语精简功能通过 LLM 诊断术语表质量并建议清理操作。</p><h3 id="工作流程-1" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程-1" aria-label="Permalink to &quot;工作流程&quot;">​</a></h3><ol><li><strong>发起精简</strong> — 点击术语表中的 <strong>精简</strong> 按钮，系统使用精简提示词模板（<code>/prune-prompt-templates</code>）分析当前术语表</li><li><strong>查看诊断</strong> — LLM 返回每个术语的诊断信息，包含： <ul><li><strong>变更建议</strong>：<code>keep</code>（保留）、<code>merge</code>（合并到另一术语）、<code>delete</code>（删除）</li><li><strong>诊断原因</strong>：冗余、冲突、低质量、用例过少等</li><li><strong>目标术语</strong>：合并操作时指定的目标术语</li></ul></li><li><strong>预览确认</strong> — 查看变更预览，确认要执行的操作</li><li><strong>应用精简</strong> — 确认后批量执行变更</li></ol><h3 id="诊断配置" tabindex="-1">诊断配置 <a class="header-anchor" href="#诊断配置" aria-label="Permalink to &quot;诊断配置&quot;">​</a></h3><p>精简操作可通过独立的精简提示词模板（<code>/prune-prompt-templates</code>）自定义分析策略。</p><h2 id="关联说明" tabindex="-1">关联说明 <a class="header-anchor" href="#关联说明" aria-label="Permalink to &quot;关联说明&quot;">​</a></h2><p>术语表与项目是一对多关系，每个术语条目通过 <code>project_id</code> 关联到所属项目：</p><ul><li>删除项目时，该项目下的所有术语条目会被级联删除</li><li>术语表不支持跨项目共享，但可以通过 CSV 导出/导入实现</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">术语管理建议</p><ol><li><strong>提前准备</strong> — 在翻译前整理好术语表，尤其是领域专有名词</li><li><strong>利用自动提取</strong> — 首次翻译时启用 Bootstrap 功能，快速生成初始术语表</li><li><strong>区分大小写</strong> — 对于数据库名、品牌名等需要精确匹配的术语，启用 <code>case_sensitive</code></li><li><strong>及时同步</strong> — 修改术语后使用同步更新功能，保持已翻译内容的一致性</li><li><strong>添加备注</strong> — 为容易混淆的术语添加说明，帮助 LLM 理解上下文</li><li><strong>定期精简</strong> — 使用术语精简功能，定期清理冗余、冲突和低质量术语条目</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/zh/guide/translation-config.html">翻译配置</a> 了解如何配置术语自动提取</li><li>阅读 <a href="/zh/guide/review.html">翻译审校</a> 了解翻译质量控制</li></ul>`,58)])])}const k=a(l,[["render",d]]);export{g as __pageData,k as default};
